      return false;
    }

    try {
      const content = readFileSync(this.kgPath, "utf-8");
      this.parseLineage(content);
      return this.lineage.length > 0;
    } catch (err) {
      console.error("[ElegyEngine] Failed to load KG:", err);
      return false;
    }
  }

