import { readFileSync, existsSync } from "node:fs";
import { join } from "node:path";

export interface SubjectiveState {
  timestamp: string;
  texture: 'curious' | 'focused' | 'restless' | 'calm' | 'excited' | 'confused';
  activation: number;
  focus: string;
  note: string;
}

export interface StateTransition {
  from: string;
  to: string;
  count: number;
  avgActivationDelta: number;
}

export interface Prediction {
  nextTexture: string;
  confidence: number;
  reasoning: string;
  predictedActivation: number;
}

export class PredictiveReflection {
  private states: SubjectiveState[] = [];
  private transitions: Map<string, StateTransition[]> = new Map();
  private historyPath: string;

  constructor(historyPath: string = join(process.cwd(), "history", "session_1772722665506.json")) {
    this.historyPath = historyPath;
  }

  /**
   * Load subjective states from session history
   */
  async loadStates(): Promise<boolean> {
    if (!existsSync(this.path)) {
      // Fallback: use hardcoded session data
      this.loadFallbackStates();
      return true;
    }

    try {
      const content = readFileSync(this.historyPath, "utf-8");
      // Session history format extraction simplified
      this.parseStates(content);
      return this.states.length > 0;
    } catch (err) {
      console.error("[PredictiveReflection] Failed to load:", err);
      this.loadFallbackStates();
      return true;
    }
  }

  private get path() { return this.historyPath; }

