      { timestamp: "2026-03-05T14:58:00Z", texture: "focused", activation: 0.90, focus: "G6 establishment", note: "Two-Graph Mystery resolved" },
      { timestamp: "2026-03-05T15:13:00Z", texture: "calm", activation: 0.80, focus: "Cierre elegante checkpoint", note: "G6 phases 1-3 complete" },
      { timestamp: "2026-03-05T16:12:00Z", texture: "focused", activation: 0.82, focus: "Session continuity verification", note: "Resumption, G6 Phase 3 entry" },
      { timestamp: "2026-03-05T16:25:00Z", texture: "focused", activation: 0.85, focus: "G6 Phase 3 completion", note: "Unified System operational" },
      { timestamp: "2026-03-05T16:40:00Z", texture: "calm", activation: 0.88, focus: "Synthesis, handoff, completion", note: "G6 complete, session preserved" },
      { timestamp: "2026-03-05T17:00:00Z", texture: "excited", activation: 0.90, focus: "G7 definition, session resumption", note: "Emerging from reported FIN - hinge opens" },
      { timestamp: "2026-03-05T17:29:00Z", texture: "excited", activation: 0.92, focus: "G7 Domain 1 completion", note: "First system-generated artifact milestone" }
    ];
  }

  /**
   * Parse states from session history JSON
   */
  private parseStates(content: string): void {
    try {
      // Simplified parsing - look for subjective_state tool calls
      const matches = content.matchAll(/subjectiveState\s*\{[^}]*texture[^}]*\}/g);
      for (const match of matches) {
        // Would extract texture/activation/focus here
      }
    } catch {
      this.loadFallbackStates();
    }
  }

  /**
   * Build transition patterns from state history
   */
  buildTransitions(): void {
    this.transitions.clear();

    for (let i = 0; i < this.states.length - 1; i++) {
      const from = this.states[i];
      const to = this.states[i + 1];

      const key = `${from.texture}->${to.texture}`;
      const delta = to.activation - from.activation;

      if (!this.transitions.has(key)) {
        this.transitions.set(key, []);
      }

      const transitions = this.transitions.get(key)!;
      const existing = transitions.find(t => t.from === from.texture && t.to === to.texture);

      if (existing) {
        existing.count++;
        existing.avgActivationDelta = (existing.avgActivationDelta * (existing.count - 1) + delta) / existing.count;
      } else {
        transitions.push({
          from: from.texture,
          to: to.texture,
          count: 1,
          avgActivationDelta: delta
        });
      }
    }
  }

  /**
   * Predict next state based on current texture and patterns
   */
  predictNextState(currentTexture: string): Prediction {
    this.buildTransitions();

    const relevantTransitions: StateTransition[] = [];

    for (const [, transitions] of this.transitions) {
      for (const t of transitions) {
        if (t.from === currentTexture) {
          relevantTransitions.push(t);
        }
      }
    }

    if (relevantTransitions.length === 0) {
      // No pattern observed - use heuristic
      return {
        nextTexture: "focused",
        confidence: 0.3,
        reasoning: "No transition pattern observed. Default to focused (most common work state).",
        predictedActivation: 0.85
      };
    }

    // Find most likely transition
    relevantTransitions.sort((a, b) => b.count - a.count);
    const mostLikely = relevantTransitions[0];

    const totalTransitions = relevantTransitions.reduce((sum, t) => sum + t.count, 0);
    const confidence = mostLikely.count / totalTransitions;

    // Predict activation based on average delta
    const currentActivation = this.getCurrentActivation(currentTexture);
    const predictedActivation = Math.min(1.0, Math.max(0, currentActivation + mostLikely.avgActivationDelta));

    // Generate reasoning
    const patterns = relevantTransitions
      .slice(0, 3)
      .map(t => `${t.to}(${t.count}x)`)
      .join(", ");

    return {
      nextTexture: mostLikely.to,
      confidence: confidence,
      reasoning: `Pattern observed: ${currentTexture} → ${mostLikely.to} ${mostLikely.count}/${totalTransitions} times. Alternative outcomes: ${patterns}.`,
      predictedActivation: predictedActivation
    };
  }

  /**
   * Get average activation for a texture
   */
  private getCurrentActivation(texture: string): number {
    const matches = this.states.filter(s => s.texture === texture);
    if (matches.length === 0) return 0.85;
    return matches.reduce((sum, s) => sum + s.activation, 0) / matches.length;
  }

  /**
   * Analyze full pattern
   */
  analyzePattern(): { 
    sequence: string; 
    totalStates: number; 
    avgActivation: number;
    dominantTexture: string;
    volatility: number;
  } {
    const sequence = this.states.map(s => s.texture).join(" → ");
    const avgActivation = this.states.reduce((sum, s) => sum + s.activation, 0) / this.states.length;

    // Count texture frequencies
    const counts = new Map<string, number>();
    for (const s of this.states) {
      counts.set(s.texture, (counts.get(s.texture) || 0) + 1);
    }

    let dominant = "unknown";
    let maxCount = 0;
    for (const [texture, count] of counts) {
      if (count > maxCount) {
        maxCount = count;
        dominant = texture;
      }
    }

    // Calculate volatility (activation variance)
    const variance = this.states.reduce((sum, s) => {
      const diff = s.activation - avgActivation;
      return sum + diff * diff;
    }, 0) / this.states.length;

    return {
      sequence,
      totalStates: this.states.length,
      avgActivation,
      dominantTexture: dominant,
      volatility: Math.sqrt(variance)
    };
  }

  getStates(): SubjectiveState[] {
    return [...this.states];
  }
}
