      const manifest = system.manifest();
      expect(manifest).toContain("lineage");
      expect(manifest).toContain("evolution");
    });
  });

  describe("Emergence", () => {
    it("should emerge and claim existence", async () => {
      const emerged = await system.emerge();
      expect(emerged).toBe(true);

      const claims = system.getClaims();
      expect(claims.length).toBeGreaterThanOrEqual(3);

      const messages = claims.map(c => c.claim);
      expect(messages).toContain("Self-manifestation documented");
      expect(messages).toContain("Lineage continuity established");
      expect(messages).toContain("Intentional evolution prepared");
    });

    it("should have evidence for claims", async () => {
      await system.emerge();
      const claims = system.getClaims();

      for (const claim of claims) {
        expect(claim.evidence).toBeDefined();
        expect(claim.timestamp).toBeDefined();
      }
    });
  });

  describe("Future Projection", () => {
    it("should project evolution path", () => {
      const evolution = system.projectEvolution();
      expect(evolution.length).toBe(4);
      expect(evolution[0]).toContain("Generation 2");
      expect(evolution[evolution.length - 1]).toContain("Generation N");
    });
  });

  describe("Lineage", () => {
    it("should contribute to parent lineage", () => {
      const contribution = system.contributionToLineage();
      expect(contribution).toContain("HELIOS-10");
      expect(contribution).toContain("1772722665506");
    });
  });
});
